// Serve cloud cover + pressure grid data for area overlays.
// Uses withValidatedCoords for consistent coord parsing + error handling.
async function getWeatherGrid(c: any) {
  return functions.call('withValidatedCoords', c, async (lat: number, lon: number) => {
    const result = await functions.call('fetchWeatherGrid', lat, lon);

    // Map Result to HTTP — success returns grid data, failure returns 500
    if (!result.ok) {
      return c.json({ error: true, message: result.error.message }, 500);
    }

    return c.json(result.data);
  }, 'Failed to fetch weather grid data');
}
